class HybridWebViewController: UIViewController {
    
    private var webView: WKWebView!
    private var progressView: UIProgressView!
    private let allowedDomains = ["yourdomain.com", "www.yourdomain.com"]
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        setupProgressView()
        loadWebsite()
    }
    
    private func setupWebView() {
        let contentController = WKUserContentController()
        
        contentController.add(self, name: "camera")
        contentController.add(self, name: "pushNotifications")
        contentController.add(self, name: "inAppPurchase")
        contentController.add(self, name: "log")
        
        let configuration = WKWebViewConfiguration()
        configuration.userContentController = contentController
        configuration.preferences.javaScriptEnabled = true
        configuration.preferences.javaScriptCanOpenWindowsAutomatically = false
        configuration.allowsInlineMediaPlayback = true
        
        if #available(iOS 14.0, *) {
            configuration.defaultWebpagePreferences.allowsContentJavaScript = true
        }
        
        webView = WKWebView(frame: .zero, configuration: configuration)
        webView.navigationDelegate = self
        webView.uiDelegate = self
        webView.translatesAutoresizingMaskIntoConstraints = false
        webView.allowsBackForwardNavigationGestures = true
        
        view.addSubview(webView)
        
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        webView.addObserver(self, forKeyPath: #keyPath(WKWebView.estimatedProgress), options: .new, context: nil)
    }
    
    private func setupProgressView() {
        progressView = UIProgressView(progressViewStyle: .default)
        progressView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(progressView)
        
        NSLayoutConstraint.activate([
            progressView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            progressView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            progressView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            progressView.heightAnchor.constraint(equalToConstant: 2)
        ])
    }
    
    private func loadWebsite() {
        guard let url = URL(string: "https://yourdomain.com") else { return }
        
        var request = URLRequest(url: url)
        request.cachePolicy = .reloadIgnoringLocalCacheData
        request.setValue("HybridApp/1.0", forHTTPHeaderField: "User-Agent")
        
        webView.load(request)
    }
    
    override func observeValue(forKeyPath keyPath: String?, of object: Any?, change: [NSKeyValueChangeKey : Any]?, context: UnsafeMutableRawPointer?) {
        if keyPath == "estimatedProgress" {
            progressView.progress = Float(webView.estimatedProgress)
            progressView.isHidden = webView.estimatedProgress >= 1.0
        }
    }
    
    private func isURLAllowed(_ url: URL) -> Bool {
        guard let host = url.host else { return false }
        return allowedDomains.contains(host)
    }
    
    private func handleCameraRequest(message: [String: Any], callback: @escaping (String) -> Void) {
        let cameraAuthStatus = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch cameraAuthStatus {
        case .authorized:
            presentImagePicker(callback: callback)
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    if granted {
                        self?.presentImagePicker(callback: callback)
                    } else {
                        callback("{\"success\": false, \"error\": \"Camera permission denied\"}")
                    }
                }
            }
        case .denied, .restricted:
            callback("{\"success\": false, \"error\": \"Camera permission denied\"}")
        @unknown default:
            callback("{\"success\": false, \"error\": \"Unknown camera status\"}")
        }
    }
    
    private func presentImagePicker(callback: @escaping (String) -> Void) {
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.allowsEditing = false
        
        imageCaptureCallback = callback
        present(picker, animated: true)
    }
    
    private var imageCaptureCallback: ((String) -> Void)?
    
    private func handlePushNotificationRequest(message: [String: Any], callback: @escaping (String) -> Void) {
        UNUserNotificationCenter.current().getNotificationSettings { settings in
            DispatchQueue.main.async {
                switch settings.authorizationStatus {
                case .authorized, .provisional:
                    self.registerForPushNotifications(callback: callback)
                case .notDetermined:
                    UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
                        DispatchQueue.main.async {
                            if granted {
                                self.registerForPushNotifications(callback: callback)
                            } else {
                                callback("{\"success\": false, \"error\": \"Push notification permission denied\"}")
                            }
                        }
                    }
                case .denied:
                    callback("{\"success\": false, \"error\": \"Push notification permission denied\"}")
                @unknown default:
                    callback("{\"success\": false, \"error\": \"Unknown notification status\"}")
                }
            }
        }
    }
    
    private func registerForPushNotifications(callback: @escaping (String) -> Void) {
        UIApplication.shared.registerForRemoteNotifications()
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
            if let token = UserDefaults.standard.string(forKey: "deviceToken") {
                callback("{\"success\": true, \"token\": \"\(token)\"}")
            } else {
                callback("{\"success\": true, \"message\": \"Registration in progress\"}")
            }
        }
    }
    
    private func handleInAppPurchase(message: [String: Any], callback: @escaping (String) -> Void) {
        guard let productId = message["productId"] as? String else {
            callback("{\"success\": false, \"error\": \"Missing productId\"}")
            return
        }
        
        let request = SKProductsRequest(productIdentifiers: [productId])
        let purchaseHandler = InAppPurchaseHandler(callback: callback)
        request.delegate = purchaseHandler
        request.start()
        
        self.purchaseHandler = purchaseHandler
    }
    
    private var purchaseHandler: InAppPurchaseHandler?
    
    deinit {
        webView.removeObserver(self, forKeyPath: #keyPath(WKWebView.estimatedProgress))
    }
