extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        let callback: (String) -> Void = { [weak self] result in
            let script = "window.nativeCallback('\(message.name)', \(result));"
            self?.webView.evaluateJavaScript(script, completionHandler: nil)
        }
        
        switch message.name {
        case "camera":
            handleCameraRequest(message: body, callback: callback)
        case "pushNotifications":
            handlePushNotificationRequest(message: body, callback: callback)
        case "inAppPurchase":
            handleInAppPurchase(message: body, callback: callback)
        case "log":
            if let logMessage = body["message"] as? String {
                print("[WebView Log]: \(logMessage)")
            }
        default:
            break
        }
    }
}

extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        if url.scheme == "https" && isURLAllowed(url) {
            decisionHandler(.allow)
        } else if url.scheme == "tel" || url.scheme == "mailto" {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url)
            }
            decisionHandler(.cancel)
        } else {
            decisionHandler(.cancel)
        }
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        progressView.isHidden = true
        
        let jsInterface = """
        window.nativeApp = {
            requestCamera: function() {
                window.webkit.messageHandlers.camera.postMessage({});
            },
            requestPushNotifications: function() {
                window.webkit.messageHandlers.pushNotifications.postMessage({});
            },
            purchaseProduct: function(productId) {
                window.webkit.messageHandlers.inAppPurchase.postMessage({productId: productId});
            },
            log: function(message) {
                window.webkit.messageHandlers.log.postMessage({message: message});
            }
        };
        
        window.nativeCallback = function(action, result) {
            if (window.nativeCallbacks && window.nativeCallbacks[action]) {
                window.nativeCallbacks[action](result);
            }
        };
        
        window.nativeCallbacks = {};
        """
        
        webView.evaluateJavaScript(jsInterface, completionHandler: nil)
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        progressView.isHidden = true
        showError(message: "Failed to load page: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

