class InAppPurchaseHandler: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    private let callback: (String) -> Void
    private var product: SKProduct?
    
    init(callback: @escaping (String) -> Void) {
        self.callback = callback
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        guard let product = response.products.first else {
            callback("{\"success\": false, \"error\": \"Product not found\"}")
            return
        }
        
        self.product = product
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                callback("{\"success\": true, \"transactionId\": \"\(transaction.transactionIdentifier ?? "")\"}")
                SKPaymentQueue.default().finishTransaction(transaction)
                SKPaymentQueue.default().remove(self)
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Unknown error"
                callback("{\"success\": false, \"error\": \"\(errorMessage)\"}")
                SKPaymentQueue.default().finishTransaction(transaction)
                SKPaymentQueue.default().remove(self)
            case .restored:
                callback("{\"success\": true, \"restored\": true}")
                SKPaymentQueue.default().finishTransaction(transaction)
                SKPaymentQueue.default().remove(self)
            default:
                break
            }
        }
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
}